VALUES
  ('cpa-moex-01568', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1年1月1日大樑公司的長期負債包含面額$900,000、利率10%、X5年1月1日到期的應付公司債， 未攤銷溢價$48,000，付息日為1月1日及7月1日，採直線法攤銷。大樑公司持有小叮公司80%的 股權。X1年1月2日，小叮公司以$612,000的價格從債券市場中，購買大樑公司流通在外面額$600,000 的債券。大樑公司及小叮公司X1年度合併綜合損益表上，債券的推定贖回損益為何？', '["利得$20,000", "利得$36,000", "損失$8,000", "損失$20,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01569', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '承上題，大樑公司及小叮公司X2年12月31日合併資產負債表上，大樑公司的應付公司債加上未攤 銷溢價後的餘額應為：', '["$300,000", "$308,000", "$312,000", "$316,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01570', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司持有乙公司 60%股權。本年度甲公司出售存貨給乙公司，銷貨毛利至年底尚未實現之金額為 $100,000。乙公司去年亦曾銷貨給甲公司，至本年度方實現的毛利金額為$80,000。所得稅稅率為25%。 試問：本年度合併遞延所得稅資產有何變化？', '["增加$13,000", "減少$13,000", "增加$5,000", "減少$5,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01571', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1年初臺北公司持有臺中公司80%股權，臺中公司持有臺南公司90%股權。當年不含投資收益之個 別淨利分別為：臺北公司$420,000；臺中公司$280,000；臺南公司$280,000。假設取得時各投資之移 轉對價均等於被投資公司可辨認淨資產公允價值比例，且被投資公司各項可辨認資產及負債之公允 價值均與帳面金額相當。前述臺南公司之淨利包含了出售給臺中公司商品之未實現毛利$56,000。X1 年 度控制權益淨利為何？', '["$706,670", "$755,980", "$805,280", "$815,770"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01572', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '母公司直接從子公司現金增資購買新股以增加持股比例，合併現金流量表應如何表達？', '["列於營業活動項下", "列於投資活動項下", "列於籌資活動項下", "無須於合併現金流量表中表達"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01573', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X1 年初臺北公司以$240,000 取得臺中公司 60%股權，採權益法處理該投資，當日臺中公司之權益 $200,000，包括普通股股本$80,000（每股面額$10）及保留盈餘$120,000，且除設備低估外，並無其 他未攤銷差額，該設備尚可使用十年，採用直線法折舊。臺中公司X6年初的保留盈餘為$175,000， 上半年獲利$25,000。臺北公司於X6年7月1日以$300,000出售其對臺中公司之所有持股，試問出 售損益金額為何？', '["$12,000", "$60,000", "$78,000", "$87,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01574', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '母公司取得子公司特別股時，若所支付對價之公允價值低於子公司該部分特別股於合併報表之帳面 金額，有關該差額之敘述，下列何者正確？', '["減少合併保留盈餘", "增加合併淨利", "增加資本公積", "減少特別股投資成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01575', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '臺北公司於X1年初以$360,000購入臺中公司60%股權，採權益法處理該項投資，並依非控制權益之 公允價值$240,000衡量非控制權益，當日臺中公司之權益$450,000。臺北公司於X4年初以$200,000 另自非控制權益股東取得臺中公司20%股權，當時臺中公司權益為$700,000，係保留盈餘增加所致。 兩次取得股權時，臺中公司各項可辨認資產及負債帳面金額均等於公允價值。X4年底合併報表列示 之商譽為何？', '["$0", "$60,000", "$100,000", "$150,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01576', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年1月1日以$800,000取得乙公司80%之股權，當日乙公司權益包括股本$300,000（每 股面額$10），保留盈餘$650,000，除未入帳專利權$50,000（剩餘效益年限為5年）外，當日乙公司 其他可辨認資產與負債之帳面金額均等於公允價值。甲公司依可辨認淨資產之比例衡量非控制權益。 X2年12月31日乙公司之權益包括股本$300,000，保留盈餘$750,000。乙公司於X3年1月1日以每 股$35之價格發行新股10,000股，甲公司認購其中的2,000股。甲公司採權益法處理其對乙公司之投 資。試問X3年1月1日乙公司發行新股後，甲公司帳上「投資乙公司」帳戶餘額為：', '["$934,000", "$929,500", "$910,000", "$858,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01577', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司之功能性貨幣為新臺幣，其美國分公司之存貨全由總公司依成本發貨，X5年中總公司發貨至 美國分公司資料分別如下：3月1日發貨8,000美元（當時匯率32.1），9月1日發貨12,000美元 （當時匯率32.3）。若X5年底及X5年度平均匯率分別為33.5、33.2，美國分公司之功能性貨幣為 美元，則分公司之報表換算為新臺幣後之總公司來貨金額為何？', '["$670,000", "$664,000", "$644,400", "$20,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01578', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司對高度很有可能發生預期交易之避險，列於其他權益之避險工具損益，在下列那個情形下， 應該立即列入當期損益？', '["甲公司取消原指定之避險", "預期交易預計不會發生時", "避險工具到期時", "避險工具解約時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01579', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '乙公司簽訂一項零成本遠期合約，該公司一年後必須以合約規定之固定金額現金購買固定數量之本 身權益工具。則簽約日乙公司應：', '["以該選擇權公允價值認列金融負債", "以合約規定固定金額現金之折現值認列金融負債", "以簽約日公允價值認列將於交割日發行之本身權益工具", "無須認列負債，僅須於合約到期日記錄購買庫藏股票"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01580', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '下列何種狀況下的嵌入式衍生工具與主契約之經濟特性及風險並非緊密關聯？', '["嵌入於雙重貨幣債券之外幣衍生工具", "發行具利率上下限之浮動利率公司債時，市場利率為3%，該債券之利率下限為4%", "某石油公司向印尼採購原油，所簽之以印尼盾（印尼幣）計價原油購買合約，其所嵌入之外幣衍 生工具", "租賃契約之租金與承租人之相關銷售數量連動，此租約中嵌入之衍生工具"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01581', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '甲公司於X1年11月7日以$240,000購買以乙公司普通股為標的之認購權證，作為持有供交易之金 融資產，此權證讓甲公司可以按每股$60 之履約價格購買 30,000 股之乙公司普通股，此權證的失效 日期為X2年1月31日。X1年11月7日、X1年12月31日與X2年1月31日乙公司普通股之市 價分別為$60、$65與$64。經評估X1年底此權證之時間價值為$180,000，甲公司應認列X1年度之 「透過損益按公允價值衡量之金融資產損益」為何？', '["損失$30,000", "損失$60,000", "利益$90,000", "利益$120,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01582', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '總公司將商品轉予分公司時通常以成本、成本加價或零售價作為轉撥價格，下列敘述何者錯誤？', '["總公司若以成本加價方式將商品轉予分公司，則所有銷貨毛利便不會僅歸屬於分公司，有助於評 估分公司之績效", "總公司若以零售價或商品正常售價將商品轉予分公司，則分公司帳上之存貨餘額等於其存貨盤點 之零售金額，可以警示管理當局存貨的管理是否適當", "總公司若以成本將商品轉予分公司，則所有銷貨毛利均歸屬於分公司，將有助於評估總公司之績效", "當總公司與分公司間商品之移轉計價係採成本時，「運交分公司存貨」與「來自總公司存貨」兩 科目之金額會相等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01583', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '臺北總公司於臺中設有一分公司，對外採購一律由總公司負責，分公司所需進貨皆由總公司以成本 加價20%發貨給分公司。X7年底分公司帳上之結帳分錄如下： 銷貨收入    1,000,000 存貨    300,000 存貨    240,000 總公司來貨    840,000 費用    150,000 總公司往來    70,000 X7年度分公司依總公司原始進貨成本計算之淨利金額為何？', '["$70,000", "$100,000", "$120,000", "$200,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01584', 'cpa', 'cpa-moex-102-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '方育慈善基金會在X1年3月20日獲得一項無條件捐款承諾，金額為$200,000，限制用於購置設備。 基金會在X1年10月20日實際收到捐款，並在X2年3月20日以捐款來購買辦公設備。方育慈善 基金會應於何時認列捐贈收入？', '["X1年3月20日", "X1年10月20日", "X1年12月31日", "X2年3月20日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "2668c8a9c638", "answer_pdf_sha1": "348a53ad9661", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL);
